output.sparql:
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
SELECT ?film ?filmLabel WHERE {
  wd:Q21290349 wdt:P161 ?film .
  ?film wdt:P31 wd:Q11424 .
  ?film rdfs:label ?filmLabel .
  FILTER(lang(?filmLabel) = 'en')
  .
  ?film p:P161 ?castStatement .
  ?castStatement ps:P161 wd:Q21290349 .
  {
    ?castStatement pq:P453 wd:Q7393755 .
  } UNION {
    ?castStatement pq:P1477 ?charName .
    FILTER regex(?charName , "murk" , "i")
  }
  FILTER EXISTS {
    ?film wdt:P136 wd:Q181102
  }
}
LIMIT 1

