  ?film wdt:P161 wd:Q21290349 . # Film has Ludi Lin as cast member
  ?film wdt:P136 wd:Q181102 . # Genre is superhero film
  ?film p:P161 ?statement .
  ?statement ps:P161 wd:Q21290349 .
  {
    ?statement pq:P453 ?character .
    ?character rdfs:label ?characterLabel .
    FILTER (lang(?characterLabel) = "en" && LCASE(?characterLabel) = "murk") .
